_plot_methods = {}

def __init_subclass__(cls, **kwargs):
    super().__init_subclass__(**kwargs)
    cls._plot_methods = {}

@classmethod
def register_plot(cls, name):
    def decorator(func):
        cls._plot_methods[name] = func
        return func
    return decorator

def plot(self, name, *args, **kwargs):
    return self._plot_methods[name](self, *args, **kwargs)

